const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1280, height: 720 }, deviceScaleFactor: 1 });
  const logs = [];
  page.on('console', msg => logs.push("'`${msg.type()}: ${msg.text()}`));
  page.on('"'pageerror', err => logs.push("'`pageerror: ${err.message}`));
  await page.goto('"'http://localhost:4173/', { waitUntil: 'networkidle' });
  await page.screenshot({ path: '/tmp/starwake-menu.png', fullPage: true });
  await page.click('#startBtn');
  await page.keyboard.down('Space');
  await page.keyboard.down('ArrowUp');
  await page.waitForTimeout(900);
  await page.keyboard.up('ArrowUp');
  await page.keyboard.down('ArrowDown');
  await page.waitForTimeout(900);
  await page.keyboard.up('ArrowDown');
  await page.keyboard.up('Space');
  await page.screenshot({ path: '/tmp/starwake-playing.png', fullPage: true });
  const data = await page.evaluate(() => {
    const canvas = document.querySelector('canvas');
    const ctx = canvas.getContext('webgl2') || canvas.getContext('webgl');
    return {
      title: document.title,
      menuHidden: document.querySelector('#menu').classList.contains('hidden'),
      score: document.querySelector('#score').textContent,
      canvas: { width: canvas.width, height: canvas.height },
      webgl: Boolean(ctx)
    };
  });
  await browser.close();
  console.log(JSON.stringify({ data, logs }, null, 2));
})().catch(err => { console.error(err); process.exit(1); });
